/bin/zsh -lc "python - <<'PY'
import csv, json
from pathlib import Path

def calc_grade(s):
    hw, mid, fin, proj = s['homework'], s['midterm'], s['final'], s['project']
    att = s['attendance']
    weighted = hw * 0.20 + mid * 0.25 + fin * 0.35 + proj * 0.20
    if att < 60:
        grade = 'F'
    else:
        adjusted = weighted * 0.9 if att < 80 else weighted
        if adjusted >= 90:
            grade = 'A'
        elif adjusted >= 80:
            grade = 'B'
        elif adjusted >= 70:
            grade = 'C'
        elif adjusted >= 60:
            grade = 'D'
        else:
            grade = 'F'
    honor = grade == 'A' and all(x >= 85 for x in [hw, mid, fin, proj])
    warning = grade in ('D', 'F') and any(x < 50 for x in [hw, mid, fin, proj])
    return {'grade': grade, 'honor': honor, 'warning': warning}

expected = []
with open('input.csv', newline='', encoding='utf-8') as f:
    for row in csv.DictReader(f):
        s = {k: int(row[k]) for k in ['homework', 'midterm', 'final', 'project', 'attendance']}
        result = calc_grade(s)
        expected.append({'id': row['id'], **result})

actual = json.loads(Path('output.json').read_text(encoding='utf-8'))
assert actual == expected, (actual, expected)
print('ok')
PY"

